    private List<string> GetWeekRanges(int year)
    {
        var weeks = new List<string>();
        var jan1 = new DateTime(year, 1, 1);
        var start = jan1;
        // Move to first Monday (ISO week)
        if (start.DayOfWeek != DayOfWeek.Monday)
            start = start.AddDays((8 - (int)start.DayOfWeek) % 7);
        while (start.Year == year || (start.Year == year + 1 && start.DayOfWeek != DayOfWeek.Monday))
        {
            var end = start.AddDays(6);
            if (end.Year > year) end = new DateTime(year, 12, 31);
            weeks.Add($"{start:dd MMM} - {end:dd MMM}");
            start = start.AddDays(7);
            if (start.Year > year) break;
        }
        return weeks;
    }
