                    var startStr = parts[0].Trim() + " " + year;
                    var endStr = parts[1].Trim() + " " + year;
                    if (DateTime.TryParse(startStr, out var weekStart) && DateTime.TryParse(endStr, out var weekEnd))
                    {
                        rows = rows.Where(r =>
                        {
                            var dt = ParseDate(r.Date);
                            return dt.HasValue && dt.Value.Date >= weekStart.Date && dt.Value.Date <= weekEnd.Date;
                        });
                    }
                }
            }
            else if (selectedReport == "monthly" && selectedMonthIndex >= 0)
            {
                var month = selectedMonthIndex + 1;
                var year = selectedMonthYear;
                rows = rows.Where(r =>
                {
                    var dt = ParseDate(r.Date);
                    return dt.HasValue && dt.Value.Month == month && dt.Value.Year == year;
                });
            }
            else if (selectedReport == "yearly")
            {
                var year = selectedYearlyYear;
                rows = rows.Where(r =>
                {
                    var dt = ParseDate(r.Date);
                    return dt.HasValue && dt.Value.Year == year;
                });
            }
            return rows;
        }
    }
