    private DateTime? ParseDate(string? dateStr)
    {
        if (string.IsNullOrWhiteSpace(dateStr)) return null;
        string[] formats = { "dd-MM-yyyy", "dd/MM/yyyy", "yyyy-MM-dd", "yyyy/MM/dd", "MM-dd-yyyy", "MM/dd/yyyy" };
        if (DateTime.TryParseExact(dateStr, formats, System.Globalization.CultureInfo.InvariantCulture, System.Globalization.DateTimeStyles.None, out var dt))
            return dt;
        if (DateTime.TryParse(dateStr, out dt))
            return dt;
        return null;
    }

    private string FormatDate(string? dateStr)
    {
        var dt = ParseDate(dateStr);
        return dt?.ToString("dd-MMM-yyyy") ?? dateStr ?? "";
    }

